#!/usr/bin/env node
// Bulk importer: walks media-import/<category>/*, uploads each unique file
// to Sanity once, and tags it with every category folder it was found in
// (same file dropped in multiple folders -> one document with multiple
// categories, not multiple documents).
//
// Filenames are expected in the form:
//   <category>_by_<author>_<number>.<ext>
// e.g. black-white_by_X-iO_1000.JPG
// <number> only exists to keep filenames unique on disk; it is not used as
// the on-site sort order. <author> is read straight from the filename.
//
// Images get alt text + caption generated by the Gemini API (free tier --
// a 6s delay is inserted between calls to stay under rate limits), via the
// shared logic in scripts/gemini-metadata.mjs -- the same function used by
// backfill-metadata.mjs for documents already in Sanity. Videos are uploaded
// with a plain fallback alt/caption (no Gemini video understanding yet).
//
// By default every category folder present under media-import/ is scanned.
// --replace=<category> deletes every existing document tagged with that
// category before uploading, AND restricts scanning to just that category's
// folder (so it doesn't touch or re-upload anything else). To scan a
// different set of folders than what --replace targets, pass --only=
// explicitly.
//
// Usage (from site/):
//   npm run import-media
//   npm run import-media -- ../media-import              (custom source folder)
//   npm run import-media -- --replace=black-white         (delete + rebuild
//     ONLY the black-white category; other folders are not scanned)
//   npm run import-media -- --replace=black-white,berlin  (multiple categories)
//   npm run import-media -- --only=black-white            (scan just this
//     folder, no deletion)

import { config } from "dotenv";
config({ path: ".env.local" });

import { createClient } from "@sanity/client";
import { createHash } from "node:crypto";
import { readdirSync, readFileSync, statSync } from "node:fs";
import { basename, extname, join } from "node:path";
import { generateAltAndCaption, sleep, GEMINI_DELAY_MS } from "./gemini-metadata.mjs";

// Keep in sync with src/lib/categories.ts.
const CATEGORIES = [
  "home",
  "architecture",
  "black-white",
  "color",
  "food",
  "places",
  "berlin",
];

const IMAGE_EXTENSIONS = new Set([".jpg", ".jpeg", ".png", ".webp", ".gif"]);
const VIDEO_EXTENSIONS = new Set([".mov", ".mp4", ".webm", ".m4v"]);

const projectId = process.env.NEXT_PUBLIC_SANITY_PROJECT_ID;
const dataset = process.env.NEXT_PUBLIC_SANITY_DATASET;
const token = process.env.SANITY_API_TOKEN;

if (!projectId || !dataset || !token) {
  console.error(
    "Missing NEXT_PUBLIC_SANITY_PROJECT_ID, NEXT_PUBLIC_SANITY_DATASET, or SANITY_API_TOKEN in site/.env.local"
  );
  process.exit(1);
}
if (!process.env.GEMINI_API_KEY) {
  console.error("Missing GEMINI_API_KEY in site/.env.local");
  process.exit(1);
}

const client = createClient({
  projectId,
  dataset,
  apiVersion: "2024-01-01",
  token,
  useCdn: false,
});

let importDirArg = "../media-import";
let replaceCategories = [];
let onlyCategories = null;
for (const arg of process.argv.slice(2)) {
  if (arg.startsWith("--replace=")) {
    replaceCategories = arg
      .slice("--replace=".length)
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean);
  } else if (arg.startsWith("--only=")) {
    onlyCategories = arg
      .slice("--only=".length)
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean);
  } else {
    importDirArg = arg;
  }
}
// Replacing a category implies scanning only that category, unless --only
// was passed explicitly to say otherwise.
if (!onlyCategories && replaceCategories.length) {
  onlyCategories = replaceCategories;
}
const categoriesToScan = onlyCategories || CATEGORIES;
const rootDir = join(process.cwd(), importDirArg);

function humanize(text) {
  return text.replace(/[-_]+/g, " ").trim();
}

function hashFile(path) {
  return createHash("sha256").update(readFileSync(path)).digest("hex");
}

// "black-white_by_X-iO_1000" -> { author: "X-iO", number: "1000" }
function parseFilename(filename) {
  const base = basename(filename, extname(filename));
  const byIdx = base.indexOf("_by_");
  if (byIdx === -1) return null;
  const rest = base.slice(byIdx + "_by_".length);
  const lastUnderscore = rest.lastIndexOf("_");
  if (lastUnderscore === -1) return null;
  const author = rest.slice(0, lastUnderscore);
  const number = rest.slice(lastUnderscore + 1);
  if (!author || !number) return null;
  return { author, number };
}

// --- Replace: delete existing docs tagged with the given categories -----

if (replaceCategories.length) {
  for (const category of replaceCategories) {
    const ids = await client.fetch(
      `*[_type == "mediaItem" && $category in categories]._id`,
      { category }
    );
    if (ids.length === 0) {
      console.log(`No existing documents tagged "${category}" to delete.`);
      continue;
    }
    console.log(
      `Deleting ${ids.length} existing document(s) tagged "${category}"...`
    );
    const tx = client.transaction();
    for (const id of ids) tx.delete(id);
    await tx.commit();
  }
  console.log();
}

// --- Scan media-import/ (only the categories in scope) --------------------

console.log(`Scanning categories: ${categoriesToScan.join(", ")}\n`);

const byHash = new Map(); // hash -> { path, filename, ext, isVideo, categories, author, number }

for (const category of categoriesToScan) {
  const dir = join(rootDir, category);
  let entries;
  try {
    entries = readdirSync(dir);
  } catch {
    continue; // folder doesn't exist yet, skip
  }
  for (const entry of entries) {
    const ext = extname(entry).toLowerCase();
    const isImage = IMAGE_EXTENSIONS.has(ext);
    const isVideo = VIDEO_EXTENSIONS.has(ext);
    if (!isImage && !isVideo) continue;
    const fullPath = join(dir, entry);
    if (!statSync(fullPath).isFile()) continue;

    const hash = hashFile(fullPath);
    if (!byHash.has(hash)) {
      const parsed = parseFilename(entry);
      byHash.set(hash, {
        path: fullPath,
        filename: entry,
        ext,
        isVideo,
        categories: new Set(),
        author: parsed?.author,
        number: parsed?.number,
      });
    }
    byHash.get(hash).categories.add(category);
  }
}

if (byHash.size === 0) {
  console.log(
    `No images/videos found under ${rootDir} for ${categoriesToScan.join(", ")}.`
  );
  process.exit(0);
}

console.log(`Found ${byHash.size} unique file(s) in ${rootDir}\n`);

let i = 0;
for (const [hash, info] of byHash) {
  i++;
  const docId = `mediaItem-${hash.slice(0, 16)}`;
  const categories = Array.from(info.categories);
  const primaryCategory = categories[0];
  const title = info.number
    ? `${humanize(primaryCategory)} ${info.number}`
    : humanize(info.filename);

  console.log(`[${i}/${byHash.size}] ${info.filename} -> ${categories.join(", ")}`);

  const asset = await client.assets.upload(
    info.isVideo ? "file" : "image",
    readFileSync(info.path),
    { filename: info.filename }
  );

  let alt = title;
  let caption;
  if (!info.isVideo) {
    try {
      const generated = await generateAltAndCaption(asset.url);
      alt = generated.alt;
      caption = generated.caption;
    } catch (err) {
      console.warn(`  Gemini metadata failed, falling back to title: ${err.message}`);
    } finally {
      await sleep(GEMINI_DELAY_MS);
    }
  }

  await client.createOrReplace({
    _id: docId,
    _type: "mediaItem",
    title,
    mediaType: info.isVideo ? "video" : "image",
    categories,
    alt,
    ...(caption ? { caption } : {}),
    author: info.author || "X-iO",
    order: i,
    ...(info.isVideo
      ? { video: { _type: "file", asset: { _type: "reference", _ref: asset._id } } }
      : { image: { _type: "image", asset: { _type: "reference", _ref: asset._id } } }),
  });
}

console.log("\nDone. Check the Studio (/studio) to review titles, alt text, captions, and ordering.");
